import{_ as o,o as a,c as t,ae as l}from"./chunks/framework.BEtfQoF7.js";const h=JSON.parse('{"title":"인증","description":"Claude Code에 로그인하고 개인, 팀 및 조직을 위한 인증을 구성합니다.","frontmatter":{"title":"인증","description":"Claude Code에 로그인하고 개인, 팀 및 조직을 위한 인증을 구성합니다."},"headers":[],"relativePath":"authentication.md","filePath":"authentication.md","lastUpdated":1776155129000}'),d={name:"authentication.md"};function r(c,e,s,i,n,u){return a(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="인증" tabindex="-1">인증 <a class="header-anchor" href="#인증" aria-label="Permalink to &quot;인증&quot;">​</a></h1><p>Claude Code는 설정에 따라 여러 인증 방법을 지원합니다. 개인 사용자는 Claude.ai 계정으로 로그인할 수 있으며, 팀은 Claude for Teams 또는 Enterprise, Claude Console, 또는 Amazon Bedrock, Google Vertex AI, Microsoft Foundry와 같은 클라우드 제공자를 사용할 수 있습니다.</p><h2 id="claude-code에-로그인" tabindex="-1">Claude Code에 로그인 <a class="header-anchor" href="#claude-code에-로그인" aria-label="Permalink to &quot;Claude Code에 로그인&quot;">​</a></h2><p><a href="/claude-code-docs-ko/setup.html#install-claude-code">Claude Code를 설치</a>한 후 터미널에서 <code>claude</code>를 실행하세요. 처음 실행 시 Claude Code가 브라우저 창을 열어 로그인할 수 있게 합니다.</p><p>브라우저가 자동으로 열리지 않으면 <code>c</code>를 눌러 로그인 URL을 클립보드에 복사한 다음 브라우저에 붙여넣으세요.</p><p>로그인 후 브라우저가 리디렉션되지 않고 로그인 코드를 표시하는 경우, 터미널의 <code>Paste code here if prompted</code> 프롬프트에 코드를 붙여넣으세요.</p><p>다음 계정 유형 중 하나로 인증할 수 있습니다:</p><ul><li><strong>Claude Pro 또는 Max 구독</strong>: Claude.ai 계정으로 로그인합니다. <a href="https://claude.com/pricing?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=authentication_pro_max" target="_blank" rel="noreferrer">claude.com/pricing</a>에서 구독하세요.</li><li><strong>Claude for Teams 또는 Enterprise</strong>: 팀 관리자가 초대한 Claude.ai 계정으로 로그인합니다.</li><li><strong>Claude Console</strong>: Console 자격 증명으로 로그인합니다. 관리자가 먼저 <a href="#claude-console-인증">사용자를 초대</a>해야 합니다.</li><li><strong>클라우드 제공자</strong>: 조직에서 <a href="/claude-code-docs-ko/amazon-bedrock.html">Amazon Bedrock</a>, <a href="/claude-code-docs-ko/google-vertex-ai.html">Google Vertex AI</a> 또는 <a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a>를 사용하는 경우, <code>claude</code>를 실행하기 전에 필요한 환경 변수를 설정하세요. 브라우저 로그인이 필요하지 않습니다.</li></ul><p>로그아웃하고 재인증하려면 Claude Code 프롬프트에서 <code>/logout</code>을 입력하세요.</p><p>로그인에 문제가 있는 경우 <a href="/claude-code-docs-ko/troubleshooting.html#authentication-issues">인증 문제 해결</a>을 참조하세요.</p><h2 id="팀-인증-설정" tabindex="-1">팀 인증 설정 <a class="header-anchor" href="#팀-인증-설정" aria-label="Permalink to &quot;팀 인증 설정&quot;">​</a></h2><p>팀 및 조직의 경우 다음 방법 중 하나로 Claude Code 접근을 구성할 수 있습니다:</p><ul><li><a href="#claude-for-teams-또는-enterprise">Claude for Teams 또는 Enterprise</a> - 대부분의 팀에 권장</li><li><a href="#claude-console-인증">Claude Console</a></li><li><a href="/claude-code-docs-ko/amazon-bedrock.html">Amazon Bedrock</a></li><li><a href="/claude-code-docs-ko/google-vertex-ai.html">Google Vertex AI</a></li><li><a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry</a></li></ul><h3 id="claude-for-teams-또는-enterprise" tabindex="-1">Claude for Teams 또는 Enterprise <a class="header-anchor" href="#claude-for-teams-또는-enterprise" aria-label="Permalink to &quot;Claude for Teams 또는 Enterprise&quot;">​</a></h3><p><a href="https://claude.com/pricing?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=authentication_teams#team-&amp;-enterprise" target="_blank" rel="noreferrer">Claude for Teams</a>와 <a href="https://anthropic.com/contact-sales?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=authentication_enterprise" target="_blank" rel="noreferrer">Claude for Enterprise</a>는 Claude Code를 사용하는 조직에 최적의 경험을 제공합니다. 팀 구성원은 중앙 집중식 청구 및 팀 관리와 함께 Claude Code와 웹의 Claude에 모두 접근할 수 있습니다.</p><ul><li><strong>Claude for Teams</strong>: 협업 기능, 관리자 도구, 청구 관리가 포함된 셀프 서비스 플랜입니다. 소규모 팀에 적합합니다.</li><li><strong>Claude for Enterprise</strong>: SSO, 도메인 캡처, 역할 기반 권한, 컴플라이언스 API, 조직 전체 Claude Code 구성을 위한 관리형 정책 설정이 추가됩니다. 보안 및 컴플라이언스 요구사항이 있는 대규모 조직에 적합합니다.</li></ul><ol><li><p><strong>구독</strong>: <a href="https://claude.com/pricing?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=authentication_teams_step#team-&amp;-enterprise" target="_blank" rel="noreferrer">Claude for Teams</a>를 구독하거나 <a href="https://anthropic.com/contact-sales?utm_source=claude_code&amp;utm_medium=docs&amp;utm_content=authentication_enterprise_step" target="_blank" rel="noreferrer">Claude for Enterprise</a>는 영업팀에 문의하세요.</p></li><li><p><strong>팀 구성원 초대</strong>: 관리자 대시보드에서 팀 구성원을 초대합니다.</p></li><li><p><strong>설치 및 로그인</strong>: 팀 구성원이 Claude Code를 설치하고 Claude.ai 계정으로 로그인합니다.</p></li></ol><h3 id="claude-console-인증" tabindex="-1">Claude Console 인증 <a class="header-anchor" href="#claude-console-인증" aria-label="Permalink to &quot;Claude Console 인증&quot;">​</a></h3><p>API 기반 청구를 선호하는 조직의 경우 Claude Console을 통해 접근을 설정할 수 있습니다.</p><ol><li><p><strong>Console 계정 생성 또는 사용</strong>: 기존 Claude Console 계정을 사용하거나 새로 만듭니다.</p></li><li><p><strong>사용자 추가</strong>: 다음 방법 중 하나로 사용자를 추가할 수 있습니다:</p><ul><li>Console 내에서 사용자 일괄 초대: Settings -&gt; Members -&gt; Invite</li><li><a href="https://support.claude.com/en/articles/13132885-setting-up-single-sign-on-sso" target="_blank" rel="noreferrer">SSO 설정</a></li></ul></li><li><p><strong>역할 할당</strong>: 사용자를 초대할 때 다음 중 하나를 할당합니다:</p><ul><li><strong>Claude Code</strong> 역할: 사용자가 Claude Code API 키만 생성 가능</li><li><strong>Developer</strong> 역할: 사용자가 모든 종류의 API 키 생성 가능</li></ul></li><li><p><strong>사용자 설정 완료</strong>: 초대된 각 사용자는 다음을 수행해야 합니다:</p><ul><li>Console 초대 수락</li><li><a href="/claude-code-docs-ko/setup.html#system-requirements">시스템 요구사항 확인</a></li><li><a href="/claude-code-docs-ko/setup.html#install-claude-code">Claude Code 설치</a></li><li>Console 계정 자격 증명으로 로그인</li></ul></li></ol><h3 id="클라우드-제공자-인증" tabindex="-1">클라우드 제공자 인증 <a class="header-anchor" href="#클라우드-제공자-인증" aria-label="Permalink to &quot;클라우드 제공자 인증&quot;">​</a></h3><p>Amazon Bedrock, Google Vertex AI 또는 Microsoft Foundry를 사용하는 팀의 경우:</p><ol><li><p><strong>제공자 설정 따르기</strong>: <a href="/claude-code-docs-ko/amazon-bedrock.html">Bedrock 문서</a>, <a href="/claude-code-docs-ko/google-vertex-ai.html">Vertex 문서</a> 또는 <a href="/claude-code-docs-ko/microsoft-foundry.html">Microsoft Foundry 문서</a>를 참조하세요.</p></li><li><p><strong>구성 배포</strong>: 환경 변수와 클라우드 자격 증명 생성 안내를 사용자에게 배포합니다. <a href="/claude-code-docs-ko/settings.html">구성 관리 방법</a>에서 자세한 내용을 확인하세요.</p></li><li><p><strong>Claude Code 설치</strong>: 사용자가 <a href="/claude-code-docs-ko/setup.html#install-claude-code">Claude Code를 설치</a>할 수 있습니다.</p></li></ol><h2 id="자격-증명-관리" tabindex="-1">자격 증명 관리 <a class="header-anchor" href="#자격-증명-관리" aria-label="Permalink to &quot;자격 증명 관리&quot;">​</a></h2><p>Claude Code는 인증 자격 증명을 안전하게 관리합니다:</p><ul><li><strong>저장 위치</strong>: macOS에서는 암호화된 macOS Keychain에 자격 증명이 저장됩니다. Linux와 Windows에서는 <code>~/.claude/.credentials.json</code>에 저장되거나, <code>$CLAUDE_CONFIG_DIR</code> 변수가 설정된 경우 해당 경로에 저장됩니다. Linux에서는 파일이 모드 <code>0600</code>으로 작성되며, Windows에서는 사용자 프로필 디렉터리의 액세스 제어를 상속합니다.</li><li><strong>지원되는 인증 유형</strong>: Claude.ai 자격 증명, Claude API 자격 증명, Azure Auth, Bedrock Auth, Vertex Auth.</li><li><strong>커스텀 자격 증명 스크립트</strong>: <a href="/claude-code-docs-ko/settings.html#available-settings"><code>apiKeyHelper</code></a> 설정을 통해 API 키를 반환하는 셸 스크립트를 실행하도록 구성할 수 있습니다.</li><li><strong>갱신 주기</strong>: 기본적으로 <code>apiKeyHelper</code>는 5분 후 또는 HTTP 401 응답 시 호출됩니다. <code>CLAUDE_CODE_API_KEY_HELPER_TTL_MS</code> 환경 변수로 커스텀 갱신 주기를 설정하세요.</li><li><strong>느린 헬퍼 알림</strong>: <code>apiKeyHelper</code>가 키를 반환하는 데 10초 이상 걸리면 Claude Code가 프롬프트 바에 경과 시간을 보여주는 경고 알림을 표시합니다. 이 알림이 자주 표시되면 자격 증명 스크립트를 최적화할 수 있는지 확인하세요.</li></ul><p><code>apiKeyHelper</code>, <code>ANTHROPIC_API_KEY</code>, <code>ANTHROPIC_AUTH_TOKEN</code>은 터미널 CLI 세션에만 적용됩니다. Claude Desktop 및 원격 세션은 OAuth만 사용하며 <code>apiKeyHelper</code>를 호출하거나 API 키 환경 변수를 읽지 않습니다.</p><h3 id="인증-우선순위" tabindex="-1">인증 우선순위 <a class="header-anchor" href="#인증-우선순위" aria-label="Permalink to &quot;인증 우선순위&quot;">​</a></h3><p>여러 자격 증명이 있는 경우 Claude Code는 다음 순서로 선택합니다:</p><ol><li>클라우드 제공자 자격 증명 - <code>CLAUDE_CODE_USE_BEDROCK</code>, <code>CLAUDE_CODE_USE_VERTEX</code> 또는 <code>CLAUDE_CODE_USE_FOUNDRY</code>가 설정된 경우. 설정은 <a href="/claude-code-docs-ko/third-party-integrations.html">서드파티 연동</a>을 참조하세요.</li><li><code>ANTHROPIC_AUTH_TOKEN</code> 환경 변수. <code>Authorization: Bearer</code> 헤더로 전송됩니다. Anthropic API 키 대신 Bearer 토큰으로 인증하는 <a href="/claude-code-docs-ko/llm-gateway.html">LLM 게이트웨이 또는 프록시</a>를 통해 라우팅할 때 사용합니다.</li><li><code>ANTHROPIC_API_KEY</code> 환경 변수. <code>X-Api-Key</code> 헤더로 전송됩니다. <a href="https://platform.claude.com" target="_blank" rel="noreferrer">Claude Console</a>에서 발급받은 키로 Anthropic API에 직접 접근할 때 사용합니다. 대화형 모드에서는 키 승인 또는 거부를 한 번 묻고 선택이 기억됩니다. 나중에 변경하려면 <code>/config</code>의 &quot;Use custom API key&quot; 토글을 사용하세요. 비대화형 모드(<code>-p</code>)에서는 키가 있으면 항상 사용됩니다.</li><li><a href="/claude-code-docs-ko/settings.html#available-settings"><code>apiKeyHelper</code></a> 스크립트 출력. Vault에서 가져온 단기 토큰과 같은 동적 또는 교체되는 자격 증명에 사용합니다.</li><li><code>CLAUDE_CODE_OAUTH_TOKEN</code> 환경 변수. <a href="#장기-토큰-생성"><code>claude setup-token</code></a>으로 생성된 장기 OAuth 토큰입니다. 브라우저 로그인이 불가능한 CI 파이프라인 및 스크립트에 사용합니다.</li><li><code>/login</code>의 구독 OAuth 자격 증명. Claude Pro, Max, Team, Enterprise 사용자의 기본값입니다.</li></ol><p>활성 Claude 구독이 있지만 환경에 <code>ANTHROPIC_API_KEY</code>도 설정되어 있는 경우, 승인 후 API 키가 우선합니다. 키가 비활성화되었거나 만료된 조직에 속하면 인증 실패가 발생할 수 있습니다. 구독으로 폴백하려면 <code>unset ANTHROPIC_API_KEY</code>를 실행하고, <code>/status</code>에서 어떤 방법이 활성 상태인지 확인하세요.</p><p><a href="/claude-code-docs-ko/claude-code-on-the-web.html">웹의 Claude Code</a>는 항상 구독 자격 증명을 사용합니다. 샌드박스 환경의 <code>ANTHROPIC_API_KEY</code>와 <code>ANTHROPIC_AUTH_TOKEN</code>은 이를 재정의하지 않습니다.</p><h3 id="장기-토큰-생성" tabindex="-1">장기 토큰 생성 <a class="header-anchor" href="#장기-토큰-생성" aria-label="Permalink to &quot;장기 토큰 생성&quot;">​</a></h3><p>대화형 브라우저 로그인이 불가능한 CI 파이프라인, 스크립트 또는 기타 환경의 경우 <code>claude setup-token</code>으로 1년 유효 OAuth 토큰을 생성하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">claude</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup-token</span></span></code></pre></div><p>이 명령은 OAuth 인증을 안내하고 토큰을 터미널에 출력합니다. 토큰은 어디에도 저장되지 않으므로, 복사하여 인증이 필요한 곳에 <code>CLAUDE_CODE_OAUTH_TOKEN</code> 환경 변수로 설정하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAUDE_CODE_OAUTH_TOKEN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your-token</span></span></code></pre></div><p>이 토큰은 Claude 구독으로 인증하며 Pro, Max, Team 또는 Enterprise 플랜이 필요합니다. 추론 전용으로 범위가 지정되며 <a href="/claude-code-docs-ko/remote-control.html">Remote Control</a> 세션을 설정할 수 없습니다.</p><p><a href="/claude-code-docs-ko/headless.html#start-faster-with-bare-mode">Bare 모드</a>는 <code>CLAUDE_CODE_OAUTH_TOKEN</code>을 읽지 않습니다. 스크립트에서 <code>--bare</code>를 사용하는 경우 <code>ANTHROPIC_API_KEY</code> 또는 <code>apiKeyHelper</code>로 인증하세요.</p>',39)])])}const m=o(d,[["render",r]]);export{h as __pageData,m as default};
